### 4.8.2 Implementation

```typescript
interface DriftThresholds {
  mileageDriftPct: number;        // 5.0
  scheduleDriftDays: number;      // 14
  fleetDriftTrainCount: number;   // 5
}

class DriftMonitorService {
  private readonly thresholds: DriftThresholds = {
    mileageDriftPct: 5.0,
    scheduleDriftDays: 14,
    fleetDriftTrainCount: 5
  };

  /**
   * Run nightly drift analysis
   */
  async runDriftAnalysis(): Promise<DriftAnalysisResult> {
    const baseline = await this.getPublishedBaseline();
    if (!baseline) {
      this.logger.info('No published baseline, skipping drift analysis');
      return { skipped: true, reason: 'No published baseline' };
    }

    const analysisDate = new Date();
    const trainAnalyses: TrainDriftAnalysis[] = [];
    const alerts: DriftAlert[] = [];

    // Analyze each train
    const trains = await this.db.query.trains.findMany({
      where: eq(trains.active, true)
    });

    for (const train of trains) {
      const analysis = await this.analyzeTrainDrift(train, baseline, analysisDate);
      trainAnalyses.push(analysis);

      // Check thresholds
      if (analysis.requiresReplan) {
        alerts.push({
          trainId: train.id,
          trainNumber: train.trainNumber,
          severity: 'HIGH',
          type: 'REPLAN_REQUIRED',
          message: analysis.replanReason,
          metrics: {
            mileageDriftPct: analysis.mileageDriftPct,
            avgPmDriftDays: analysis.avgPmDriftDays
          }
        });
      } else if (Math.abs(analysis.mileageDriftPct) > this.thresholds.mileageDriftPct * 0.7) {
        alerts.push({
          trainId: train.id,
          trainNumber: train.trainNumber,
          severity: 'MEDIUM',
          type: 'APPROACHING_THRESHOLD',
          message: `Mileage drift at ${analysis.mileageDriftPct.toFixed(1)}% (threshold: ${this.thresholds.mileageDriftPct}%)`,
          metrics: {
            mileageDriftPct: analysis.mileageDriftPct
          }
        });
      }

      // Persist analysis
      await this.persistDriftAnalysis(analysis, baseline.id, analysisDate);
    }

    // Fleet-level analysis
    const trainsRequiringReplan = trainAnalyses.filter(a => a.requiresReplan).length;

    if (trainsRequiringReplan >= this.thresholds.fleetDriftTrainCount) {
      alerts.push({
        severity: 'CRITICAL',
        type: 'FLEET_REPLAN_RECOMMENDED',
        message: `${trainsRequiringReplan} trains require replanning - consider strategic replan`,
        metrics: {
          affectedTrains: trainsRequiringReplan
        }
      });
    }

    // Send alerts
    if (alerts.length > 0) {
      await this.sendDriftAlerts(alerts);
    }

    // Broadcast to canvas
    await this.websocketHub.broadcast('drift:updated', {
      baselineId: baseline.id,
      analysisDate,
      summary: {
        totalTrains: trains.length,
        trainsWithDrift: trainAnalyses.filter(a => Math.abs(a.mileageDriftPct) > 1).length,
        trainsRequiringReplan,

