### 4.9.1 Purpose

Enable what-if scenario analysis with persistent storage and comparison capabilities.

### 4.9.2 Implementation

```typescript
class SimulationEngine {
  /**
   * Create a new scenario branched from baseline or another scenario
   */
  async createScenario(
    name: string,
    description: string,
    forkFrom: { type: 'BASELINE' | 'SCENARIO'; id: string },
    userId: string
  ): Promise<Scenario> {
    const scenario = await this.db.insert(scenarios)
      .values({
        name,
        description,
        forkedFromBaselineId: forkFrom.type === 'BASELINE' ? forkFrom.id : null,
        forkedFromScenarioId: forkFrom.type === 'SCENARIO' ? forkFrom.id : null,
        status: 'ACTIVE',
        createdBy: userId,
        expiresAt: addDays(new Date(), 30)
      })
      .returning();

    return scenario[0];
  }

  /**
   * Apply a change to a scenario (event-sourced)
   */
  async applyChange(
    scenarioId: string,
    change: ScenarioChange,
    userId: string
  ): Promise<void> {
    // Get next sequence number
    const lastDelta = await this.db.query.scenarioDeltas.findFirst({
      where: eq(scenarioDeltas.scenarioId, scenarioId),
      orderBy: desc(scenarioDeltas.sequenceNum)
    });

    const sequenceNum = (lastDelta?.sequenceNum || 0) + 1;

    // Record delta
    await this.db.insert(scenarioDeltas)
      .values({
        scenarioId,
        sequenceNum,
        deltaType: change.type,
        entityType: change.entityType,
        entityId: change.entityId,
        oldValues: change.oldValues,
        newValues: change.newValues,
        changeReason: change.reason,
        createdBy: userId
      });

    // Update scenario timestamp
    await this.db.update(scenarios)
      .set({
        lastModifiedAt: new Date(),
        expiresAt: addDays(new Date(), 30)  // Reset expiration
      })
      .where(eq(scenarios.id, scenarioId));
  }

  /**
   * Materialize a scenario (apply all deltas to get full state)
   */
  async materializeScenario(scenarioId: string): Promise<MaterializedScenario> {
    const scenario = await this.db.query.scenarios.findFirst({
      where: eq(scenarios.id, scenarioId)
    });

    if (!scenario) {
      throw new NotFoundError('Scenario not found');
    }

    // Get base state
    let basePMSchedule: PMScheduleRecord[];

    if (scenario.forkedFromBaselineId) {
      basePMSchedule = await this.db.query.baselinePmSchedule.findMany({
        where: eq(baselinePmSchedule.baselineId, scenario.forkedFromBaselineId)
      });
    } else if (scenario.forkedFromScenarioId) {
      // Recursive materialization
      const parentScenario = await this.materializeScenario(scenario.forkedFromScenarioId);
      basePMSchedule = parentScenario.pmSchedule;
    } else {
      // Fork from current production
      basePMSchedule = await this.db.query.pmSchedule.findMany({
        where: isNull(pmSchedule.scenarioId)
      });
    }

